def simulate_load():
  loads = [200, 300, 400, 500]
  count = 0
  limit = random.choice(loads)
  while True:
    time.sleep(0.1)
    count += 1
    if count > limit:
      return

def resolve_users(self, info, id=None):
    query = UserObject.get_query(info)
    Audit.create_audit_entry(info)
    if id:
      result = query.filter_by(id=id)
    else:
      result = query
    return result

